import re, glob, collections

pkgs = collections.defaultdict(dict)
for f in glob.glob('**/*.csproj', recursive=True):
    content = open(f, encoding='utf-8').read()
    for m in re.finditer(r'PackageReference\s+Include=\"([^\"]+)\"\s+Version=\"([^\"]+)\"', content):
        name, ver = m.group(1), m.group(2)
        pkgs[name][f] = ver

# Find conflicts (same package, different versions)
conflicts = {n: v for n,v in pkgs.items() if len(set(v.values())) > 1}
# No conflicts (all same version)
no_conflict = {n: list(v.values())[0] for n,v in pkgs.items() if len(set(v.values())) == 1}

print('=== VERSION CONFLICTS ===')
for pkg, files in sorted(conflicts.items()):
    print(f'{pkg}: {set(files.values())}')
    for f, v in files.items():
        print(f'  {f}: {v}')

print()
print('=== ALL PACKAGES (max version) ===')
all_pkgs = {}
for pkg, files in pkgs.items():
    versions = list(set(files.values()))
    # pick highest
    versions.sort(key=lambda v: [int(x) if x.isdigit() else x for x in re.split(r'\.', v)])
    all_pkgs[pkg] = versions[-1]
for pkg, ver in sorted(all_pkgs.items()):
    print(f'{pkg}: {ver}')
